import { products } from "../data.js";
import type { Product, ServiceResult } from "../types.js";

interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

interface ProductSummary {
  count: number;
  totalInventoryValue: number;
  averagePrice: number;
}

interface ProductListResult {
  products: Product[];
  summary: ProductSummary;
}

type EnrichedProduct = Product & { isLowStock: boolean; inventoryValue: number };

export function getProducts(filters: ProductFilters): ServiceResult<ProductListResult> {
  let filtered = [...products];

  if (filters.category) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined && !isNaN(filters.minPrice)) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined && !isNaN(filters.maxPrice)) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    success: true,
    data: {
      products: filtered,
      summary: {
        count: filtered.length,
        totalInventoryValue: Math.round(totalValue * 100) / 100,
        averagePrice: Math.round(avgPrice * 100) / 100,
      },
    },
  };
}

export function getProductById(id: number): ServiceResult<EnrichedProduct> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { success: false, error: "Product not found", status: 404 };
  }

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    success: true,
    data: { ...product, isLowStock, inventoryValue },
  };
}

export function adjustProductStock(id: number, adjustment: unknown): ServiceResult<EnrichedProduct> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { success: false, error: "Product not found", status: 404 };
  }

  if (typeof adjustment !== "number") {
    return { success: false, error: "adjustment must be a number", status: 400 };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { success: false, error: "Insufficient stock", status: 400 };
  }

  product.stock = newStock;

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

